import { Component, h, Prop, Element, Event, EventEmitter } from '@stencil/core';
import { customTwMerge } from '../../utils/utils';

@Component({
  tag: 'wdpr-navigation-header',
  shadow: true,
})
export class WdprNavigationHeader {
  @Element() el: HTMLWdprNavigationHeaderElement;

  @Prop() theme: 'WDW' | 'DLR' = 'WDW';
  @Prop() logoPath: string = '';
  @Prop({ attribute: 'a11y-label' }) a11yLabel?: string = '';

  @Prop({ mutable: true, reflect: true }) isOpen: boolean = false;
  @Prop() isGradient: boolean = false;
  @Prop() isFloating: boolean = false;
  @Prop() isInverse: boolean = false;
  @Prop() buttonLabel: string = 'Tickets';

  private _shouldRestoreFocus = false;

  @Event() wdprNavigationHeaderMenuButtonClick!: EventEmitter<void>;
  @Event() wdprNavigationHeaderCloseClick!: EventEmitter<void>;
  @Event() wdprNavigationHeaderSearchClick!: EventEmitter<void>;
  @Event() wdprNavigationHeaderButtonClick!: EventEmitter<void>;

  private get _actions(): Array<{
    iconName: string;
    a11yLabel: string;
    a11yExpanded?: 'true' | 'false';
    onClick: () => void;
  }> {
    return [
      {
        iconName: 'search',
        a11yLabel: 'Search site',
        a11yExpanded: undefined,
        onClick: this._onSearchClick,
      },
      {
        iconName: this.isOpen ? 'close-reversed' : 'menu-global-nav',
        a11yLabel: this.isOpen ? 'Close navigation menu' : 'Open navigation menu',
        a11yExpanded: this.isOpen ? 'true' : 'false',
        onClick: this._onNavigationToggleClick,
      },
    ];
  }

  private _onSearchClick = (): void => {
    this.wdprNavigationHeaderSearchClick.emit();
  };

  private _onTicketsButtonClick = (): void => {
    this.wdprNavigationHeaderButtonClick.emit();
  };

  private _onNavigationToggleClick = (): void => {
    this.isOpen = !this.isOpen;

    if (this.isOpen) {
      this.wdprNavigationHeaderMenuButtonClick.emit();

      return;
    }

    this.wdprNavigationHeaderCloseClick.emit();
    this._shouldRestoreFocus = true;
  };

  private _getToggleButton(): HTMLButtonElement | null {
    const toggle = this.el.shadowRoot?.querySelector('wdpr-icon-button[iconname="menu-global-nav"]') as HTMLElement | null;

    return (toggle?.shadowRoot?.querySelector('button') as HTMLButtonElement | null) ?? null;
  }

  componentDidRender(): void {
    if (!this._shouldRestoreFocus) return;

    this._shouldRestoreFocus = false;
    this._getToggleButton()?.focus();
  }

  private get _containerClass(): string {
    const baseContainerClass = 'flex items-center justify-between pl-150';
    const bgClass = this.isFloating ? 'bg-surface-translucent' : 'bg-surface-transparent';
    const floatingClass = this.isFloating ? 'rounded-300 elevation-xsmall-soft backdrop-blur-[calc(var(--effect-400)/2)]' : '';

    return customTwMerge(baseContainerClass, bgClass, floatingClass);
  }

  private get _iconsContainerClass(): string {
    return 'flex items-center h-[52px]';
  }

  private get _showDlrButton(): boolean {
    return this.theme === 'DLR';
  }

  private get _dlrButtonVariant(): 'primary' | 'secondary' {
    return (this.isInverse || this.isGradient) && !this.isFloating ? 'secondary' : 'primary';
  }

  private get _iconButtonVariant(): 'primary' | 'inverse' {
    return (this.isInverse || this.isGradient) && !this.isFloating ? 'inverse' : 'primary';
  }

  render() {
    return (
      <nav class={this._containerClass} aria-label={this.a11yLabel || 'Main navigation header'}>
        <figure aria-hidden="true">
          <img src={this.logoPath} />
        </figure>

        <ul class={this._iconsContainerClass} role="list">
          {this._showDlrButton && (
            <li class="px-100 py-200">
              <wdpr-button
                variant={this._dlrButtonVariant}
                size="xsmall"
                display="fit"
                a11yLabel={this.buttonLabel}
                onWdprClick={this._onTicketsButtonClick}
              >
                {this.buttonLabel}
              </wdpr-button>
            </li>
          )}
          {this._actions.map(action => (
            <li class="px-150 py-200">
              <wdpr-icon-button
                iconName={action.iconName}
                a11yLabel={action.a11yLabel}
                a11yExpanded={action.a11yExpanded}
                variant={this._iconButtonVariant}
                onClicked={action.onClick}
              />
            </li>
          ))}
        </ul>
      </nav>
    );
  }
}
